@st.cache_data(show_spinner=False)
def read_csv_bytes(file_bytes):
    import io as _io
    return pd.read_csv(_io.BytesIO(file_bytes))


def fig_to_png_bytes(fig):
    buf = io.BytesIO()
    fig.savefig(buf, format="png", dpi=300, bbox_inches="tight")
    buf.seek(0)
    return buf.getvalue()


def save_bytes(file_bytes, suffix):
    with tempfile.NamedTemporaryFile(delete=False, suffix=suffix) as tmp:
        tmp.write(file_bytes)
        return tmp.name


def load_glacier_path(uploaded_file):
    suffix = Path(uploaded_file.name).suffix.lower()
    if suffix in [".gpkg", ".geojson"]:
        return save_bytes(uploaded_file.getvalue(), suffix)
    if suffix == ".zip":
        tmpdir = tempfile.mkdtemp()
        zpath = os.path.join(tmpdir, uploaded_file.name)
        with open(zpath, "wb") as f:
            f.write(uploaded_file.getvalue())
        with zipfile.ZipFile(zpath, "r") as zf:
            zf.extractall(tmpdir)
        shp_files = list(Path(tmpdir).rglob("*.shp"))
        if not shp_files:
            raise ValueError("No shapefile found inside glacier ZIP.")
        return str(shp_files[0])
    raise ValueError("Unsupported glacier file format.")


def idw_interpolate_df(
    df,
    x_col="Longitude",
    y_col="Latitude",
    z_col="Elevation",
    cell_size=1.0,
    search_radius=0.7,
    power=2,
    sort_desc=True,
):
    required_cols = {x_col, y_col, z_col}
    if not required_cols.issubset(df.columns):
        raise ValueError(f"CSV must contain {x_col}, {y_col}, {z_col}. Found: {list(df.columns)}")

    x = df[x_col].to_numpy(dtype=float)
    y = df[y_col].to_numpy(dtype=float)
    z = df[z_col].to_numpy(dtype=float)

    valid_mask = np.isfinite(x) & np.isfinite(y) & np.isfinite(z)
    x = x[valid_mask]
    y = y[valid_mask]
    z = z[valid_mask]

    if x.size == 0:
        raise ValueError("No valid points found after cleaning.")

    minx, maxx = x.min(), x.max()
    miny, maxy = y.min(), y.max()

    pad = cell_size * 0.5
    minx -= pad
    miny -= pad
    maxx += pad
    maxy += pad

    grid_x = np.arange(minx, maxx, cell_size)
    grid_y = np.arange(miny, maxy, cell_size)
    grid_xx, grid_yy = np.meshgrid(grid_x, grid_y)
    grid_points = np.column_stack((grid_xx.ravel(), grid_yy.ravel()))

    tree = cKDTree(np.column_stack((x, y)))
    neighbors_idx = tree.query_ball_point(grid_points, r=search_radius)

    interp_z = np.full(len(grid_points), np.nan, dtype=float)

    for i, idx_list in enumerate(neighbors_idx):
        if len(idx_list) == 0:
            continue

        x_neighbors = x[idx_list]
        y_neighbors = y[idx_list]
        z_neighbors = z[idx_list]

        dx = x_neighbors - grid_points[i, 0]
        dy = y_neighbors - grid_points[i, 1]
        d = np.sqrt(dx**2 + dy**2)

        zero_mask = d == 0
        if np.any(zero_mask):
            interp_z[i] = z_neighbors[zero_mask][0]
            continue

        w = 1.0 / (d ** power)
        interp_z[i] = np.sum(w * z_neighbors) / np.sum(w)

    valid = ~np.isnan(interp_z)
    grid_valid = grid_points[valid]
    z_valid = interp_z[valid]

    out_df = pd.DataFrame({
        "Point_id": np.arange(1, len(z_valid) + 1),
        "Latitude": grid_valid[:, 1],
        "Longitude": grid_valid[:, 0],
        "Elevation": z_valid
    })

    if sort_desc:
        out_df = out_df.sort_values("Elevation", ascending=False).reset_index(drop=True)

    out_df["sorted_order"] = np.arange(1, len(out_df) + 1)
    return out_df


def csv_to_geodf_notebook(df, epsg_code):
    crs_proj = f"EPSG:{epsg_code}"
    # notebook uses Point(row.iloc[2], row.iloc[1]) after creating [Point_id, Latitude, Longitude, Elevation, sorted_order]
    gdf = df.copy()
    gdf["geometry"] = gdf.apply(lambda row: Point(row.iloc[2], row.iloc[1]), axis=1)
    return gpd.GeoDataFrame(gdf, geometry="geometry", crs=crs_proj)


def make_fig():
    fig = plt.figure()
    return fig


def clip_dem(dem_path, glacier_shp_path, output_clipped_dem):
    glacier_gdf = gpd.read_file(glacier_shp_path)
    with rasterio.open(dem_path) as dem_src:
        if glacier_gdf.crs != dem_src.crs:
            glacier_gdf = glacier_gdf.to_crs(dem_src.crs)

        clipped_dem, clipped_transform = rio_mask(dem_src, glacier_gdf.geometry, crop=True)
        clipped_meta = dem_src.meta.copy()
        clipped_meta.update({
            "driver": "GTiff",
            "height": clipped_dem.shape[1],
            "width": clipped_dem.shape[2],
            "transform": clipped_transform
        })

        with rasterio.open(output_clipped_dem, "w", **clipped_meta) as dest:
            dest.write(clipped_dem)

    return output_clipped_dem


def classify_and_calculate_area(path, elevation_interval=50, min_elevation=None, max_elevation=None):
    with rasterio.open(path) as src:
        dem_data = src.read(1)
        dem_data = dem_data[dem_data > 0]
        pixel_area = abs(src.transform[0] * src.transform[4])

    if len(dem_data) == 0:
        raise ValueError(f"No valid DEM pixels found in {path}")

    if min_elevation is None:
        min_elevation = int(np.floor(dem_data.min()))
    if max_elevation is None:
        max_elevation = int(np.ceil(dem_data.max()))

    bins = np.arange(min_elevation, max_elevation + elevation_interval, elevation_interval)
    elevation_classes = np.digitize(dem_data, bins)

    area_per_class = []
    for i in range(1, len(bins)):
        area = (elevation_classes == i).sum() * pixel_area
        area_per_class.append(area)

    return bins, area_per_class


def plot_elevation_vs_area(bins, area_per_class, title="Hypsometry"):
    mid_bins = (bins[:-1] + bins[1:]) / 2
    fig, ax = plt.subplots(figsize=(6, 6))
    ax.barh(mid_bins, area_per_class, height=30, edgecolor="black", alpha=0.9)
    ax.set_xlabel("Area (m²)", fontsize=12)
    ax.set_ylabel("Elevation (m)", fontsize=12)
    ax.set_title(title, fontsize=12)
    ax.grid(axis="x", linestyle="--", alpha=0.6)
    ax.tick_params(axis="x", labelsize=12)
    ax.set_yticks(mid_bins)
    ax.tick_params(axis="y", labelsize=12)
    plt.tight_layout()
    return fig, mid_bins


def apply_dem_bias_correction(
    geo_gdf,
    raster_file,
    corrected_dem,
    glacier_shp_path,
    output_clipped_dem,
    elevation_interval=50,
    min_elevation=None,
    max_elevation=None,
    label="DEM"
):
    geo_gdf = geo_gdf.copy()
    figures = {}

    coordinates = [(point.x, point.y) for point in geo_gdf.geometry]

    with rasterio.open(raster_file) as src:
        raster_values = list(src.sample(coordinates))
        geo_gdf["raster_raw_value"] = [val[0] for val in raster_values]

        geo_gdf["dgps_dem_diff"] = np.abs(geo_gdf["raster_raw_value"] - geo_gdf["Elevation"])
        dgps_dem_diff_avg = np.mean(geo_gdf["dgps_dem_diff"])

        fig, ax = plt.subplots(figsize=(8, 6))
        extent = [src.bounds.left, src.bounds.right, src.bounds.bottom, src.bounds.top]
        show(src, extent=extent, ax=ax, cmap="pink")
        geo_gdf.plot(ax=ax)
        ax.set_title(f"Raw DEM - {label}")
        plt.tight_layout()
        figures["raw_dem"] = fig

        profile = src.profile
        data = src.read(1)
        corrected_dem_arr = data - dgps_dem_diff_avg
        profile.update(dtype="float32")

    with rasterio.open(corrected_dem, "w", **profile) as dst:
        dst.write(corrected_dem_arr.astype("float32"), 1)

    with rasterio.open(corrected_dem) as src:
        raster_values = list(src.sample(coordinates))
        geo_gdf["raster_corr_value"] = [val[0] for val in raster_values]

        fig, ax = plt.subplots(figsize=(8, 6))
        extent = [src.bounds.left, src.bounds.right, src.bounds.bottom, src.bounds.top]
        show(src, extent=extent, ax=ax, cmap="pink")
        geo_gdf.plot(ax=ax)
        ax.set_title(f"Corrected DEM - {label}")
        plt.tight_layout()
        figures["corrected_dem"] = fig

    fig, ax = plt.subplots(figsize=(8, 5))
    ax.plot(geo_gdf["sorted_order"], geo_gdf["Elevation"], label="dGPS")
    ax.plot(geo_gdf["sorted_order"], geo_gdf["raster_raw_value"], label="DEM-Sat-Raw")
    ax.legend(fontsize=12)
    ax.set_xlabel("Samples", fontsize=12)
    ax.set_ylabel("Elevation (m)", fontsize=12)
    plt.tight_layout()
    figures["raw_line"] = fig

    geo_gdf["dem_corr"] = geo_gdf["raster_raw_value"] - dgps_dem_diff_avg

    fig, ax = plt.subplots(figsize=(8, 4))
    ax.plot(geo_gdf["sorted_order"], geo_gdf["dgps_dem_diff"])
    ax.set_xlabel("Samples")
    ax.set_ylabel("Absolute difference")
    plt.tight_layout()
    figures["abs_diff_line"] = fig

    fig, ax = plt.subplots(figsize=(8, 5))
    ax.plot(geo_gdf["sorted_order"], geo_gdf["Elevation"], label="dGPS")
    ax.plot(geo_gdf["sorted_order"], geo_gdf["raster_corr_value"], label="DEM-Sat-Correct")
    ax.legend(fontsize=12)
    ax.set_xlabel("Samples", fontsize=12)
    ax.set_ylabel("Elevation (m)", fontsize=12)
    plt.tight_layout()
    figures["corrected_line"] = fig

    fig, ax = plt.subplots(figsize=(6, 4))
    ax.hist(geo_gdf["dgps_dem_diff"], bins=50)
    ax.axvline(dgps_dem_diff_avg, color="red", ls="--", lw=2)
    ax.set_xlabel("Absolute difference")
    ax.set_ylabel("Frequency")
    plt.tight_layout()
    figures["hist_diff"] = fig

    clipped_dem = clip_dem(corrected_dem, glacier_shp_path, output_clipped_dem)
    elev_bins, area_per_class = classify_and_calculate_area(
        clipped_dem,
        elevation_interval=elevation_interval,
        min_elevation=min_elevation,
        max_elevation=max_elevation
    )
    hyps_fig, mid_bins = plot_elevation_vs_area(elev_bins, area_per_class, title=f"Hypsometry - {label}")
    figures["hypsometry"] = hyps_fig

    return {
        "geo_gdf": geo_gdf,
        "bias_mean": dgps_dem_diff_avg,
        "corrected_dem": corrected_dem,
        "clipped_dem": clipped_dem,
        "elev_bins": elev_bins,
        "mid_bins": mid_bins,
        "area_per_class": area_per_class,
        "figures": figures,
    }


def get_boundary_segments(glacier_shp_path):
    gdf = gpd.read_file(glacier_shp_path)
    boundary = gdf.geometry.boundary.unary_union
    lines = boundary.geoms if isinstance(boundary, MultiLineString) else [boundary]

    segments = []
    for line in lines:
        coords = list(line.coords)
        for i in range(len(coords) - 1):
            segments.append((coords[i], coords[i+1]))
    return segments, gdf.crs


def get_elevation_for_coords(dem_path, coords):
    with rasterio.open(dem_path) as src:
        band = src.read(1)
        values = []
        for x, y in coords:
            row, col = src.index(x, y)
            values.append(band[row, col])
    return np.array(values)


def compute_segment_band_lengths_fixed(segments, start_elev, end_elev, bins):
    avg_elevations = (start_elev + end_elev) / 2.0
    labels = [f"{int(bins[i])}-{int(bins[i+1])} m" for i in range(len(bins) - 1)]
    band_indices = np.digitize(avg_elevations, bins) - 1

    band_lengths = {}
    for (p1, p2), band_idx in zip(segments, band_indices):
        if 0 <= band_idx < len(labels):
            band = labels[band_idx]
            length = np.hypot(p2[0] - p1[0], p2[1] - p1[1])
            band_lengths[band] = band_lengths.get(band, 0) + length

    df = pd.DataFrame(list(band_lengths.items()), columns=["Elevation Band", "Boundary Length (m)"]).sort_values("Elevation Band")
    return df


def create_segment_gdf_fixed(segments, start_elev, end_elev, crs, bins):
    avg_elevations = (start_elev + end_elev) / 2.0
    labels = [f"{int(bins[i])}-{int(bins[i+1])} m" for i in range(len(bins) - 1)]
    band_indices = np.digitize(avg_elevations, bins) - 1
    bands = [labels[i] if 0 <= i < len(labels) else None for i in band_indices]
    lines = [LineString([p1, p2]) for (p1, p2) in segments]
    return gpd.GeoDataFrame({"geometry": lines, "Elevation Band": bands}, crs=crs)


def plot_segments_by_band(segment_gdf):
    fig, ax = plt.subplots(figsize=(10, 10))
    segment_gdf.plot(ax=ax, column="Elevation Band", cmap="viridis", linewidth=2, legend=True)
    ax.set_title("Glacier Boundary Segments by Elevation Band", fontsize=14)
    ax.set_axis_off()
    plt.tight_layout()
    return fig


